const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const clientID = 'your-client-id';
const clientSecret = 'your-client-secret';
const redirectURI = 'http://localhost:3000/callback';
const providerMetadataURL = 'https://provider.com/.well-known/openid-configuration';

async function getProviderConfiguration() {
  const response = await fetch(providerMetadataURL);
  return await response.json();
}

app.get('/login', async (req, res) => {
  const providerConfig = await getProviderConfiguration();
  const authorizationEndpoint = providerConfig.authorization_endpoint;
  const scope = 'openid profile email';
  const state = generateRandomString(32);

  const authURL = `${authorizationEndpoint}?response_type=code&client_id=${clientID}&redirect_uri=${encodeURIComponent(redirectURI)}&scope=${scope}&state=${state}`;
  res.redirect(authURL);
});

app.get('/callback', async (req, res) => {
  const { code, state } = req.query;
  if (!code || !state) {
    return res.status(400).send('Invalid request');
  }

  const providerConfig = await getProviderConfiguration();
  const tokenEndpoint = providerConfig.token_endpoint;

  const tokenResponse = await fetch(tokenEndpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(redirectURI)}&client_id=${clientID}`
  });

  const tokens = await tokenResponse.json();
  const idToken = tokens.id_token;

  const decodedToken = jwt.decode(idToken, { complete: true });
  const userClaims = decodedToken.payload;

  // Create user session using user claims
  req.session.user = userClaims;
  res.send('User logged in');
});

function generateRandomString(length) {
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let result = '';
  for (let i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return result;
}

